class Folder{
    int id;
    int[] subFolder;
    String name;

    public Folder(int id, int[] subFolder, String name){
        this.id = id;
        this.subFolder = subFolder;
        this.name = name;
    }
}

class PathMetaData{
    String path;
    int sourceId;
    public PathMetaData(int sourceId, String path){
        this.sourceId = sourceId;
        this.path = path;
    }
}


class FolderHandler{
    Map<Integer, Folder> folderMap;
    Map<Integer, Folder> parentMap;
    Map<Integer, PathMetaData> pathMap;
    final Map<Integer, Lock> lockMap;

    public FolderHandler(){
        this.folderMap = new ConcurrentHashMap<>();
        this.parentMap = new ConcurrentHashMap<>();;
        this.pathMap = new ConcurrentHashMap<>();;
        this.lockMap = new ConcurrentHashMap<>();
    }

    public void addPath(Folder folder){
        if(folder == null){
            System.out.println("invalid folder");
            return;
        }
        int id = folder.id;

        if(id != 0){
            folderMap.put(id, folder);
            pathMap.put(id, new PathMetaData(id, folder.name));
        }

        //parentMap update
        for(int child: folder.subFolder){
            parentMap.put(child, folder);
        }

    }


    public void printPath(int index){
        updatePath(index);
        if(!pathMap.containsKey(index) || pathMap.get(index).sourceId != 0){
            System.out.println("");
            return;
        }
        System.out.println(pathMap.get(index).path);
    }

    Lock getLock(int index){
        if(lockMap.containsKey(index)){
            return lockMap.get(index);
        }
        synchronized (lockMap){
            if(lockMap.containsKey(index)){
                return lockMap.get(index);
            }
            lockMap.put(index, new ReentrantLock());
        }
        return lockMap.get(index);
    }

    private void updatePath(int index){
        if(!folderMap.containsKey(index) || !parentMap.containsKey(index)){
            return;
        }
        if(pathMap.get(index).sourceId == 0){
            return;
        }

        //Main handling starts
        Lock lock = getLock(index);
        lock.lock();
        try{
            PathMetaData currMeta = pathMap.get(index);
            int sourceId = currMeta.sourceId;
            if(sourceId == index){
                int parentId = parentMap.get(index).id;
                if(parentId == 0){
                    currMeta.sourceId = 0;
                    currMeta.path = String.format("%s -> %s", parentMap.get(index).name, folderMap.get(index).name);
                    return;
                }
                sourceId = parentId;
            }

            updatePath(sourceId);
            setMetaData(index, sourceId);
        } finally {
            lock.unlock();
        }
    }

    private void setMetaData(int index, int sourceId){
        PathMetaData currMeta = pathMap.get(index);
        PathMetaData sourceMeta = pathMap.get(sourceId);

        currMeta.sourceId = sourceMeta.sourceId;
        currMeta.path = String.format("%s -> %s", sourceMeta.path, currMeta.path);
    }

}
